"use client";

import { useState, useEffect } from "react";
import { Plus, Trash2, Edit2, Loader2, Users, Upload, X } from "lucide-react";
import Image from "next/image";

export default function TeamManagement() {
  const [members, setMembers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editingMember, setEditingMember] = useState<any>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    fetchMembers();
  }, []);

  const fetchMembers = async () => {
    try {
      const res = await fetch("/api/team");
      const data = await res.json();
      setMembers(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (member: any) => {
    setEditingMember(member || { 
      name: "", 
      role: "", 
      imageUrl: "", 
      bio: "", 
      order: 0,
      facebookUrl: "",
      instagramUrl: "",
      linkedinUrl: ""
    });
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Delete this member?")) return;
    await fetch(`/api/team/${id}`, { method: "DELETE" });
    fetchMembers();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setUploading(true);
    const formData = new FormData();
    formData.append("file", file);

    try {
      const res = await fetch("/api/upload", { method: "POST", body: formData });
      const data = await res.json();
      setEditingMember({ ...editingMember, imageUrl: data.url });
    } catch (error) {
      alert("Upload failed");
    } finally {
      setUploading(false);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    const method = editingMember.id ? "PUT" : "POST";
    const url = editingMember.id ? `/api/team/${editingMember.id}` : "/api/team";

    await fetch(url, {
      method,
      body: JSON.stringify(editingMember),
      headers: { "Content-Type": "application/json" },
    });

    setIsModalOpen(false);
    fetchMembers();
  };

  if (loading) return <div className="flex justify-center p-12"><Loader2 className="animate-spin" /></div>;

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Team Members</h1>
          <p className="text-slate-500 font-medium">Manage faculty and staff profiles.</p>
        </div>
        <button 
          onClick={() => handleEdit(null)}
          className="bg-primary text-white font-black px-6 py-3 rounded-2xl shadow-lg flex items-center gap-2"
        >
          <Plus className="w-5 h-5" />
          Add Member
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {members.map((member: any) => (
          <div key={member.id} className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm hover:shadow-md transition-all group">
            <div className="flex items-center gap-4 mb-4">
               <div className="size-16 rounded-2xl bg-slate-100 overflow-hidden relative">
                  {member.imageUrl ? (
                    <Image src={member.imageUrl} alt="" fill className="object-cover" />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center text-slate-300">
                       <Users className="w-8 h-8" />
                    </div>
                  )}
               </div>
               <div>
                  <h3 className="font-black text-slate-900">{member.name}</h3>
                  <p className="text-sm text-primary font-bold">{member.role}</p>
               </div>
            </div>
            {member.bio && <p className="text-sm text-slate-500 line-clamp-2 mb-6 font-medium leading-relaxed">{member.bio}</p>}
            <div className="flex justify-end gap-2 pt-4 border-t border-slate-50">
               <button onClick={() => handleEdit(member)} className="p-2 text-slate-400 hover:text-primary transition-colors">
                  <Edit2 className="w-4 h-4" />
               </button>
               <button onClick={() => handleDelete(member.id)} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                  <Trash2 className="w-4 h-4" />
               </button>
            </div>
          </div>
        ))}
      </div>

      {/* Simple Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-lg rounded-[32px] shadow-2xl border border-slate-100 p-8 space-y-6 animate-in zoom-in-95 duration-200">
             <div className="flex justify-between items-center">
                <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">{editingMember.id ? "Edit Member" : "Add New Member"}</h2>
                <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-900"><X className="w-6 h-6" /></button>
             </div>

             <form onSubmit={handleSave} className="space-y-6">
                <div className="flex justify-center">
                   <div className="relative size-24 bg-slate-50 rounded-3xl overflow-hidden border-2 border-dashed border-slate-200 cursor-pointer group">
                      {editingMember.imageUrl ? (
                        <Image src={editingMember.imageUrl} alt="" fill className="object-cover" />
                      ) : (
                        <div className="w-full h-full flex flex-col items-center justify-center text-slate-400 gap-1">
                           <Upload className="w-6 h-6" />
                           <span className="text-[10px] font-black uppercase tracking-widest">Photo</span>
                        </div>
                      )}
                      <input type="file" onChange={handleImageUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                      {uploading && <div className="absolute inset-0 bg-white/80 flex items-center justify-center"><Loader2 className="animate-spin text-primary" /></div>}
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                   <div className="col-span-1">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Full Name</label>
                      <input 
                        type="text" 
                        required 
                        value={editingMember.name} 
                        onChange={(e) => setEditingMember({...editingMember, name: e.target.value})}
                        className="w-full px-4 py-3 bg-slate-50 border-transparent rounded-xl focus:bg-white focus:border-primary transition-all text-sm outline-none font-bold"
                      />
                   </div>
                   <div className="col-span-1">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Role/Designation</label>
                      <input 
                        type="text" 
                        required 
                        value={editingMember.role} 
                        onChange={(e) => setEditingMember({...editingMember, role: e.target.value})}
                        className="w-full px-4 py-3 bg-slate-50 border-transparent rounded-xl focus:bg-white focus:border-primary transition-all text-sm outline-none font-medium"
                      />
                   </div>
                </div>

                <div className="grid grid-cols-3 gap-4">
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Facebook</label>
                      <input 
                        type="text" 
                        value={editingMember.facebookUrl || ""} 
                        onChange={(e) => setEditingMember({...editingMember, facebookUrl: e.target.value})}
                        className="w-full px-4 py-3 bg-slate-50 border-transparent rounded-xl focus:bg-white focus:border-primary transition-all text-xs outline-none font-medium"
                        placeholder="https://..."
                      />
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Instagram</label>
                      <input 
                        type="text" 
                        value={editingMember.instagramUrl || ""} 
                        onChange={(e) => setEditingMember({...editingMember, instagramUrl: e.target.value})}
                        className="w-full px-4 py-3 bg-slate-50 border-transparent rounded-xl focus:bg-white focus:border-primary transition-all text-xs outline-none font-medium"
                        placeholder="https://..."
                      />
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">LinkedIn</label>
                      <input 
                        type="text" 
                        value={editingMember.linkedinUrl || ""} 
                        onChange={(e) => setEditingMember({...editingMember, linkedinUrl: e.target.value})}
                        className="w-full px-4 py-3 bg-slate-50 border-transparent rounded-xl focus:bg-white focus:border-primary transition-all text-xs outline-none font-medium"
                        placeholder="https://..."
                      />
                   </div>
                </div>

                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Biography</label>
                   <textarea 
                     rows={3}
                     value={editingMember.bio} 
                     onChange={(e) => setEditingMember({...editingMember, bio: e.target.value})}
                     className="w-full px-4 py-3 bg-slate-50 border-transparent rounded-xl focus:bg-white focus:border-primary transition-all text-sm outline-none font-medium resize-none"
                   ></textarea>
                </div>

                <button type="submit" className="w-full bg-primary text-white font-black py-4 rounded-2xl shadow-lg shadow-primary/20 hover:shadow-primary/40 transition-all uppercase tracking-widest text-xs">
                   Save Member
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
}
